using System;
using System.Linq;
using System.Reflection;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;

// Look for Cosmos-specific extension methods related to "id" or "discriminator"
var cosmosAssembly = typeof(CosmosDbContextOptionsExtensions).Assembly;

var allTypes = cosmosAssembly.GetTypes();
foreach (var type in allTypes.Where(t => t.IsPublic))
{
    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Static | BindingFlags.Instance)
        .Where(m => m.Name.Contains("Id", StringComparison.OrdinalIgnoreCase) 
                  || m.Name.Contains("Discriminator", StringComparison.OrdinalIgnoreCase))
        .Where(m => m.DeclaringType == type);

    foreach (var m in methods)
    {
        var parms = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"{type.Name}.{m.Name}({parms})");
    }
}
